&lt;% for (const item of items) { %&gt;





      &lt;%= item.title %&gt;


        &lt;%= item.subtitle %&gt;



        &lt;%= item.description %&gt;




         
         


            &lt;% if(item.website) { %&gt;  Website &lt;% } %&gt;
            &lt;% if(item.scholar) { %&gt;  Scholar &lt;% } %&gt;
            &lt;% if(item.linkedin) { %&gt;  LinkedIn &lt;% } %&gt;
            &lt;% if(item.bluesky) { %&gt;  Bluesky &lt;% } %&gt;
            &lt;% if(item.github) { %&gt;  GitHub &lt;% } %&gt;
            &lt;% if(item.orcid) { %&gt;  ORCID &lt;% } %&gt;





&lt;% } %&gt;
